+  if (params.profile) {
+    return params.profile;
+  }
+  if (!params.browserSession) {
+    return undefined;
+  }
+  if (params.browserSession === "agent") {
+    return DEFAULT_OPENCLAW_BROWSER_PROFILE_NAME;
